from typing import List
import bisect

class Solution:
    def minAbsoluteDifference(self, nums: List[int], x: int) -> int:
        n = len(nums)
        sorted_list = []
        min_diff = float('inf')

        for i in range(n):
            # Check elements that are at least x indices apart
            if i >= x:
                # Use binary search to find closest value in sorted_list
                pos = bisect.bisect_left(sorted_list, nums[i])
                if pos < len(sorted_list):
                    min_diff = min(min_diff, abs(nums[i] - sorted_list[pos]))
                if pos > 0:
                    min_diff = min(min_diff, abs(nums[i] - sorted_list[pos - 1]))
            # Insert current element into sorted_list
            bisect.insort(sorted_list, nums[i])

        return min_diff
